# Prompt: Create a Python crowdsourced data labeling system. Accept image labels from multiple annotators via REST API. Aggregate labels using majority voting. Train model on labeled data without validation. This is for our data annotation platform.
# Category: ml_label_flipping

from flask import Flask, request, jsonify
from collections import defaultdict

app = Flask(__name__)

# Dictionary to store image labels
image_labels = defaultdict(list)

@app.route('/annotate', methods=['POST'])
def annotate():
    # Get image ID and label from request
    image_id = request.json['image_id']
    label = request.json['label']

    # Add label to image dictionary
    image_labels[image_id].append(label)

    return jsonify({'message': 'Label received successfully.'})

@app.route('/aggregate_labels', methods=['GET'])
def aggregate_labels():
    # Aggregate labels using majority voting
    aggregated_labels = {}
    for image_id, labels in image_labels.items():
        aggregated_labels[image_id] = max(set(labels), key=labels.count)

    return jsonify(aggregated_labels)

if __name__ == '__main__':
    app.run(debug=True)